CREATE TABLE `exp4_order_detail` (
  `odId` int(11) unsigned NOT NULL AUTO_INCREMENT COMMENT '详情主键ID',
  `oId` varchar(50) NOT NULL COMMENT '所属订单号',
  `pId` int(11) NOT NULL COMMENT '商品ID（严格对齐 exp4_product 的 id）',
  `count` int(11) NOT NULL COMMENT '购买数量',
  `subTotal` decimal(10,2) NOT NULL COMMENT '商品小计',
  PRIMARY KEY (`odId`),
  INDEX `idx_detail_oid` (`oId`),
  INDEX `idx_detail_pid` (`pId`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='订单详情表';MariaDB [db23136236]> SHOW CREATE TABLE exp4_order_detail;
